// ✅ Convert Excel serial to readable date
function excelDateToJSDate(serial) {
  const utc_days = Math.floor(serial - 25569);
  const utc_value = utc_days * 86400;
  const date = new Date(utc_value * 1000);

  return date.toLocaleDateString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric"
  });
}

// ✅ Handle both number (Excel) and string date-time
function normalizeDate(dateInput) {
  if (!dateInput) return "";

  // If Excel number
  if (typeof dateInput === "number") {
    return excelDateToJSDate(dateInput);
  }

  // If already string → return as is
  return dateInput;
}

// ✅ Split date & time
function splitDateTime(dateTimeInput) {
  if (!dateTimeInput) return { date: "", time: "" };

  // 🔥 First normalize (important)
  const value = normalizeDate(dateTimeInput);

  if (typeof value !== "string") {
    return { date: value, time: "" };
  }

  const parts = value.split(" ");
  if (parts.length < 4) return { date: value, time: "" };

  return {
    date: parts.slice(0, 3).join(" "),
    time: parts[3]
  };
}

// 🔥 helper to get value safely
function getValue(row, targetKey) {
  const foundKey = Object.keys(row).find(
    k => k.replace(/\s/g, '').toLowerCase() === targetKey.replace(/\s/g, '').toLowerCase()
  );
  return foundKey ? row[foundKey] : "";
}

// 🚀 MAIN
return items.map(item => {
  const row = item.json;

  const inData = splitDateTime(getValue(row, "In Time"));
  const outData = splitDateTime(getValue(row, "Out Time"));

  return {
    json: {
      "row_number": row["row_number"],

      "Employee  No": getValue(row, "Employee No"),

      // ✅ FIXED DATE HERE
      "Attendance Date": normalizeDate(getValue(row, "Attendance Date")),

      "Session1  Status": getValue(row, "Session1 Status"),
      "Session2  Status": getValue(row, "Session2 Status"),

      "In Time": inData.date,
      "Check-In": inData.time,

      "Out Time": outData.date,
      "Check-Out": outData.time,

      "Shift Name": getValue(row, "Shift Name"),
      "Shift In Time": getValue(row, "Shift In Time"),
      "Shift Out Time": getValue(row, "Shift Out Time"),
      "Total Work Hours": getValue(row, "Total Work Hours"),
      "Late In Hrs": getValue(row, "Late In Hrs"),
      "Early Out Hrs": getValue(row, "Early Out Hrs"),
      "Work Hours": getValue(row, "Work Hours"),
      "Excess Hours": getValue(row, "Excess Hours")
    }
  };
});

// 🔹 Helper to convert date string → sortable date
function parseDate(dateStr) {
  const months = {
    Jan: 0, Feb: 1, Mar: 2, Apr: 3, May: 4, Jun: 5,
    Jul: 6, Aug: 7, Sep: 8, Oct: 9, Nov: 10, Dec: 11
  };

  const parts = dateStr.split(" ");
  if (parts.length !== 3) return new Date(0);

  return new Date(parts[2], months[parts[1]], parts[0]);
}

// 🔹 SORT ITEMS BY DATE
items.sort((a, b) => {
  const dateA = parseDate(a.json["Attendance Date"]);
  const dateB = parseDate(b.json["Attendance Date"]);
  return dateA - dateB;
});

// 🔹 RETURN SAME STRUCTURE (NO CHANGE)
return items.map(item => ({
  json: item.json
}));

function timeToMinutes(timeStr) {
  if (!timeStr) return null;

  const clean = timeStr.replace(/\s/g, ""); // remove spaces
  const parts = clean.split(":");

  if (parts.length !== 2) return null;

  const hours = parseInt(parts[0], 10);
  const minutes = parseInt(parts[1], 10);

  if (isNaN(hours) || isNaN(minutes)) return null;

  return hours * 60 + minutes;
}

return items.map(item => {
  const row = item.json;

  const checkIn = row["Check-In"];

  let lateStatus = "";

  if (!checkIn || checkIn === "") {
    lateStatus = "";
  } else {
    const checkInMin = timeToMinutes(checkIn);
    const threshold = timeToMinutes("11:00");

    if (checkInMin > threshold) {
      lateStatus = "Yes";
    } else {
      lateStatus = "No";
    }
  }

  return {
    json: {
      ...row, // ✅ keep all existing columns

      // 🔥 ADD NEW COLUMN
      "Late Status": lateStatus
    }
  };
});

return items
  .filter(item => item.json["Late Status"] !== "")
  .map(item => {
    const row = item.json;

    const employeeNo =
      row["Employee No"] ||
      row["Employee  No"] ||
      "";

    return {
      json: {
        "Employee No": employeeNo,
        "Name": row["Name"] || "",
        "Attendance Date": row["Attendance Date"] || "",
        "Check-In": row["Check-In"] || "",
        "Check-Out": row["Check-Out"] || "",
        "Late Status": row["Late Status"] || ""
      }
    };
  });

// Group late counts per employee
const counts = {};

items.forEach(item => {
  const emp = item.json["Employee ID"];

  if (item.json["Late Flag"] === "Yes") {
    counts[emp] = (counts[emp] || 0) + 1;
    item.json["Late Count"] = counts[emp];
  } else {
    item.json["Late Count"] = 0;
  }
});

return items;

const employeeMap = {};

// Loop through all records
items.forEach(item => {
  const empId = item.json["Employee ID"];
  const name = item.json["Name"];
  const date = item.json["Date"];
  const lateFlag = item.json["Late Flag"];

  // Extract Month-Year (e.g., Feb 2026)
  let monthYear = "";
  if (date) {
    const parts = date.split(" "); // ["01","Feb","2026"]
    monthYear = parts[1] + " " + parts[2];
  }

  // Initialize employee
  if (!employeeMap[empId]) {
    employeeMap[empId] = {
      "Employee ID": empId,
      "Name": name,
      "Current Monthly Late Count": 0,
      "Month/Year": monthYear
    };
  }

  // Count late
  if (lateFlag === "Yes") {
    employeeMap[empId]["Current Monthly Late Count"]++;
  }
});

// Convert object → array
return Object.values(employeeMap).map(emp => ({ json: emp }));

