return items.map(item => {
  // 🔥 Get correct text
  const text = item.json?.output?.[0]?.content?.[0]?.text || "";

  let subject = "";
  let body = "";

  // ✅ Extract Subject (handles both formats)
  const subjectMatch = text.match(/Subject[:*]*\s*(.+)/i);
  if (subjectMatch) {
    subject = subjectMatch[1].split("\n")[0].trim();
  }

  // ✅ Extract Body (multiple formats)
  if (text.includes("**Body:**")) {
    body = text.split("**Body:**")[1];
  } else if (text.includes("---")) {
    body = text.split("---")[1];
  } else {
    body = text.replace(/Subject[:*]*\s*(.+)/i, "");
  }

  // 🔥 CLEAN TEXT (REMOVE \n, \n\n, EXTRA SPACES)
  body = body
    .replace(/\n+/g, " ")   // replace all new lines with space
    .replace(/\s+/g, " ")   // remove extra spaces
    .trim();

  return {
    json: {
      Subject: subject,
      Body: body
    }
  };
});

return items.map(item => {
  let text = item.json?.output?.[0]?.content?.[0]?.text || "";

  let subject = "";
  let body = "";

  // 🟢 CASE 1: If response is JSON string
  if (text.trim().startsWith("{")) {
    try {
      const parsed = JSON.parse(text);

      subject = parsed.Subject || "";
      body = parsed.Body || "";
    } catch (e) {
      // fallback if JSON parse fails
    }
  }

  // 🟡 CASE 2: Markdown / Normal text
  if (!subject) {
    const subjectMatch = text.match(/Subject[:*"]*\s*(.+)/i);
    if (subjectMatch) {
      subject = subjectMatch[1].split("\n")[0].trim();
    }
  }

  if (!body) {
    if (text.includes("**Body:**")) {
      body = text.split("**Body:**")[1];
    } else if (text.includes("---")) {
      body = text.split("---")[1];
    } else {
      body = text.replace(/Subject[:*"]*\s*(.+)/i, "");
    }
  }

  // 🔥 CLEAN BODY (REMOVE \n, \n\n, EXTRA SPACES)
  body = body
    .replace(/\\n/g, " ")   // remove escaped \n
    .replace(/\n+/g, " ")   // remove real new lines
    .replace(/\s+/g, " ")   // remove extra spaces
    .trim();

  return {
    json: {
      Subject: subject,
      Body: body
    }
  };
});

